EXECUTE_COMMAND_TOOL = {
    "name": "execute_command",
    "description": (
        "Run a shell command and return its output. "
        "Use for running tests, builds, linters, and inspecting the environment. "
        "Do NOT use for commands that modify shared remote state (git push, deploy scripts) "
        "unless explicitly instructed."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "command": {
                "type": "string",
                "description": "The shell command to execute."
            },
            "working_directory": {
                "type": "string",
                "description": "Absolute path to the working directory. Defaults to the project root."
            },
            "timeout_seconds": {
                "type": "integer",
                "description": "Maximum seconds to wait before killing the process. Defaults to 30.",
                "default": 30
            }
        },
        "required": ["command"]
    }
}

import re
from enum import Enum

class RiskTier(Enum):
    READ_ONLY = 1    # pre-approved, no confirmation needed
    MUTATING  = 2    # agent can run, but action is logged prominently
    DANGEROUS = 3    # requires explicit user confirmation in the same turn

# Patterns for tier assignment (checked in order)
TIER_RULES = [
    # Dangerous: remote writes, destructive operations
    (RiskTier.DANGEROUS, re.compile(
        r"git push|git force|rm -rf|DROP TABLE|\bdeploy\b|\bpublish\b|curl.*-X (POST|PUT|DELETE)"
    )),
    # Read-only: introspection and verification
    (RiskTier.READ_ONLY, re.compile(
        r"^(cat|ls|find|grep|git (log|diff|status|show)|npm test|pytest|tsc|eslint|prettier)"
    )),
    # Everything else is mutating (file writes, installs, builds)
]

def classify_command(command: str) -> RiskTier:
    for tier, pattern in TIER_RULES:
        if pattern.search(command):
            return tier
    return RiskTier.MUTATING  # default to mutating if unclassified
